#include "interface.h"
#include "simdutf.h"
#include <string>
#include <vector>

namespace {

uint64_t checksum_bytes(const char* data, size_t length) {
  uint64_t hash = 1469598103934665603ULL;
  for (size_t i = 0; i < length; ++i) {
    hash ^= static_cast<uint64_t>(static_cast<unsigned char>(data[i]));
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t encode_checksum(const std::string& input) {
  if (input.empty()) {
    return 1469598103934665603ULL;
  }

  // Calculate required size for base64 output
  size_t input_len = input.size();
  size_t output_len = ((input_len + 2) / 3) * 4;

  // Use a vector or a unique_ptr for the buffer to avoid string overhead
  std::vector<char> buffer(output_len);

  // simdutf::base64_encode returns the number of bytes written
  // It handles padding automatically according to the standard
  auto result = simdutf::base64_encode(input.data(), input_len, buffer.data());

  if (result.error) {
    // This case is unlikely for base64 encoding unless buffer is too small
    return 0;
  }

  return checksum_bytes(buffer.data(), result.bytes_written);
}
